import { InlineKeyboard } from "grammy";
import { isProfileComplete } from "../services/workouts.js";

function cap(s, n) {
  s = String(s || "").trim();
  if (s.length <= n) return s;
  return s.slice(0, n);
}

export function onboardingKeyboardGoal() {
  return new InlineKeyboard()
    .text("Lose weight", "ob:goal:lose")
    .text("Gain muscle", "ob:goal:gain")
    .row()
    .text("Stay fit", "ob:goal:stay");
}

export function onboardingKeyboardLevel() {
  return new InlineKeyboard()
    .text("Beginner", "ob:lvl:beginner")
    .text("Intermediate", "ob:lvl:intermediate")
    .row()
    .text("Advanced", "ob:lvl:advanced");
}

export function onboardingKeyboardTime() {
  return new InlineKeyboard()
    .text("Morning", "ob:time:morning")
    .text("Afternoon", "ob:time:afternoon")
    .text("Evening", "ob:time:evening")
    .row()
    .text("Custom", "ob:time:custom");
}

export function needsOnboarding(user) {
  if (!user) return true;
  return !isProfileComplete(user);
}

export function nextOnboardingPrompt(user) {
  const st = user?.onboardingState || "name";
  const p = user?.profile || {};

  if (!p.name) return { state: "name" };
  if (p.age == null) return { state: "age" };
  if (!p.goal) return { state: "goal" };
  if (!p.workoutLevel) return { state: "workoutLevel" };
  if (!p.preferredWorkoutTime) return { state: "preferredWorkoutTime" };

  return { state: "done" };
}

export function renderOnboardingQuestion({ state }) {
  if (state === "name") {
    return {
      text: "Let’s get you set up.\n\nName\n- What should I call you?\n\nNext action: type your name.",
      keyboard: null
    };
  }

  if (state === "age") {
    return {
      text: "Age\n- How old are you? (Numbers only)\n- Or tap Skip if you’d rather not say.\n\nNext action: type your age or tap Skip.",
      keyboard: new InlineKeyboard().text("Skip", "ob:age:skip")
    };
  }

  if (state === "goal") {
    return {
      text: "Goal\n- What are we training for?\n\nNext action: pick one.",
      keyboard: onboardingKeyboardGoal()
    };
  }

  if (state === "workoutLevel") {
    return {
      text: "Workout level\n- How spicy do you want this to be?\n\nNext action: pick one.",
      keyboard: onboardingKeyboardLevel()
    };
  }

  if (state === "preferredWorkoutTime") {
    return {
      text: "Preferred workout time\n- When should I nudge you?\n\nNext action: pick a time window (or Custom).",
      keyboard: onboardingKeyboardTime()
    };
  }

  if (state === "customTime") {
    return {
      text: "Custom time\n- Type a time like 07:30 or 18:15 (your local time).\n\nNext action: type HH:MM.",
      keyboard: null
    };
  }

  return { text: "All set.", keyboard: null };
}

export function parseOnboardingTextInput({ state, text }) {
  const t = cap(text, 64);

  if (state === "name") {
    const name = cap(t.replace(/\s+/g, " "), 32);
    if (!name || name.length < 1) return { ok: false, error: "Please send a name (1–32 chars)." };
    return { ok: true, patch: { profile: { name } } };
  }

  if (state === "age") {
    const raw = String(t || "").trim().toLowerCase();
    if (raw === "skip") return { ok: true, patch: { profile: { age: null } } };
    const n = Number(raw);
    if (!Number.isFinite(n) || n < 10 || n > 110) {
      return { ok: false, error: "Age should be a number between 10 and 110 (or tap Skip)." };
    }
    return { ok: true, patch: { profile: { age: Math.floor(n) } } };
  }

  if (state === "customTime") {
    const m = String(t || "").trim().match(/^([01]?\d|2[0-3]):([0-5]\d)$/);
    if (!m) return { ok: false, error: "Please type a time like 07:30 or 18:15." };
    return { ok: true, patch: { profile: { preferredWorkoutTime: `${m[1].padStart(2, "0")}:${m[2]}` } } };
  }

  return { ok: false, error: "Unexpected input." };
}

export function mergeProfile(existingProfile, patchProfile) {
  return { ...(existingProfile || {}), ...(patchProfile || {}) };
}

scheduler.js.content:
import { safeErr } from "../lib/safeErr.js";
import { getIsoWeekKey } from "../lib/time.js";

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

export function startScheduler({ bot, db, intervalMs = 120000 }) {
  let stopped = false;
  let tick = 0;

  console.log("[scheduler] start", { intervalMs, hasDb: !!db });

  (async () => {
    while (!stopped) {
      tick++;
      try {
        console.log("[scheduler] cycle", { tick });
        await runWeeklyReports({ bot, db });
      } catch (e) {
        console.error("[scheduler] cycle failed", { err: safeErr(e) });
      }

      if (tick % 30 === 0) {
        const m = process.memoryUsage();
        console.log("[mem]", { rssMB: Math.round(m.rss / 1e6), heapUsedMB: Math.round(m.heapUsed / 1e6) });
      }

      await sleep(intervalMs);
    }
  })();

  return () => {
    stopped = true;
  };
}

async function runWeeklyReports({ bot, db }) {
  if (!db) return;

  const now = new Date();
  const weekKey = getIsoWeekKey(now);

  // Conservative: send at most a few per cycle to avoid long backlogs.
  const cursor = db.collection("progress").find({}).limit(10);
  const rows = await cursor.toArray();

  for (const p of rows) {
    const last = p.lastWeeklyReportAt ? new Date(p.lastWeeklyReportAt) : null;
    const lastWeekKey = last ? getIsoWeekKey(last) : "";
    if (lastWeekKey === weekKey) continue;

    // Mark first, then send (idempotent best-effort)
    await db.collection("progress").updateOne(
      { telegramUserId: p.telegramUserId },
      {
        $setOnInsert: { createdAt: new Date() },
        $set: { lastWeeklyReportAt: new Date(), updatedAt: new Date() }
      },
      { upsert: true }
    );

    try {
      await bot.api.sendMessage(
        Number(p.telegramUserId),
        "Weekly Summary\n- Your report is ready.\n\nNext action: open the bot and tap 📊 My Progress to generate details.",
        { disable_web_page_preview: true }
      );
    } catch (e) {
      console.error("[scheduler] weekly send failed", { userId: p.telegramUserId, err: safeErr(e) });
    }
  }
}

index.js.content:
import "dotenv/config";
import { run } from "@grammyjs/runner";
import { cfg } from "./lib/config.js";
import { safeErr } from "./lib/safeErr.js";

process.on("unhandledRejection", (r) => {
  console.error("[process] UnhandledRejection", { err: safeErr(r) });
  process.exit(1);
});
process.on("uncaughtException", (e) => {
  console.error("[process] UncaughtException", { err: safeErr(e) });
  process.exit(1);
});

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

async function boot() {
  console.log("[boot] start", {
    TELEGRAM_BOT_TOKEN_set: !!cfg.TELEGRAM_BOT_TOKEN,
    MONGODB_URI_set: !!cfg.MONGODB_URI,
    COOKMYBOTS_AI_ENDPOINT_set: !!cfg.COOKMYBOTS_AI_ENDPOINT,
    COOKMYBOTS_AI_KEY_set: !!cfg.COOKMYBOTS_AI_KEY,
    TZ: cfg.TZ,
    PORT: cfg.PORT,
    BASE_URL_set: !!cfg.BASE_URL
  });

  if (!cfg.TELEGRAM_BOT_TOKEN) {
    console.error("TELEGRAM_BOT_TOKEN is required. Add it in your environment and redeploy.");
    process.exit(1);
  }

  const { createBot } = await import("./bot.js");
  const { registerCommands } = await import("./commands/loader.js");
  const { startScheduler } = await import("./features/scheduler.js");

  const bot = await createBot(cfg.TELEGRAM_BOT_TOKEN);

  try {
    await bot.init();
  } catch (e) {
    console.warn("[boot] bot.init failed", { err: safeErr(e) });
  }

  await registerCommands(bot);

  try {
    await bot.api.setMyCommands([
      { command: "start", description: "Welcome & onboarding" },
      { command: "help", description: "How to use FitBuddy X" },
      { command: "reset", description: "Wipe your FitBuddy X data" }
    ]);
  } catch (e) {
    console.warn("[boot] setMyCommands failed", { err: safeErr(e) });
  }

  // Prefer long polling + runner for reliability on deploy overlap.
  let backoff = 2000;
  const maxBackoff = 20000;
  let runner = null;
  let restarting = false;

  const stopScheduler = startScheduler({ bot, db: bot?.api?.config ? bot?.api?.config : null, intervalMs: 120000 });

  async function startPolling() {
    if (restarting) return;
    restarting = true;
    try {
      try {
        await bot.api.deleteWebhook({ drop_pending_updates: true });
      } catch (e) {
        console.warn("[boot] deleteWebhook failed", { err: safeErr(e) });
      }

      console.log("[polling] start", { concurrency: 1 });
      runner = run(bot, { concurrency: 1 });

      // Reset backoff after successful start.
      backoff = 2000;
    } catch (e) {
      const err = safeErr(e);
      console.error("[polling] start failed", { err });

      // Telegram 409 happens during deploy overlap; retry with backoff.
      await sleep(backoff);
      backoff = Math.min(maxBackoff, Math.round(backoff * 2.5));
      restarting = false;
      return startPolling();
    } finally {
      restarting = false;
    }
  }

  await startPolling();

  // Keep process alive; runner handles updates.
  console.log("[boot] ready");
}

boot().catch((e) => {
  console.error("[boot] fatal", { err: safeErr(e) });
  process.exit(1);
});

ai.js.content:
import { safeErr } from "./safeErr.js";

function trimSlash(u) {
  u = String(u || "");
  while (u.endsWith("/")) u = u.slice(0, -1);
  return u;
}

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

function withTimeout(ms) {
  const ctrl = new AbortController();
  const t = setTimeout(() => ctrl.abort(), ms);
  return { ctrl, clear: () => clearTimeout(t) };
}

function pickTimeout(cfg) {
  const v = Number(cfg?.AI_TIMEOUT_MS || 600000);
  return Number.isFinite(v) && v > 0 ? v : 600000;
}

function pickModel(cfg, override) {
  const m = String(override || cfg?.AI_MODEL || "").trim();
  return m || undefined;
}

function isRetryableStatus(status) {
  return status === 408 || status === 429 || (status >= 500 && status <= 599);
}

function redact(s) {
  s = String(s || "");
  if (s.length <= 400) return s;
  return s.slice(0, 400) + "…";
}

function notConfigured(message) {
  return { ok: false, status: 412, json: null, error: message };
}

async function readJsonSafe(r) {
  const text = await r.text();
  try {
    return { text, json: JSON.parse(text) };
  } catch {
    return { text, json: null };
  }
}

export async function aiChat(cfg, { messages, model, meta } = {}, opts = {}) {
  const base = trimSlash(cfg?.COOKMYBOTS_AI_ENDPOINT || "");
  const key = String(cfg?.COOKMYBOTS_AI_KEY || "");

  if (!base || !key) return notConfigured("AI_NOT_CONFIGURED");

  const timeoutMs = Number(opts.timeoutMs || pickTimeout(cfg));
  const retries = Number.isFinite(opts.retries) ? Number(opts.retries) : Number(cfg?.AI_MAX_RETRIES || 2);

  const url = base + "/chat";
  const started = Date.now();

  console.log("[ai] chat start", { url: base, hasKey: !!key, meta: meta || {} });

  let attempt = 0;
  while (true) {
    attempt++;
    const { ctrl, clear } = withTimeout(timeoutMs);
    try {
      const r = await fetch(url, {
        method: "POST",
        headers: {
          Authorization: "Bearer " + key,
          "Content-Type": "application/json"
        },
        body: JSON.stringify({ messages, model: pickModel(cfg, model), meta: meta || undefined }),
        signal: ctrl.signal
      });

      const { text, json } = await readJsonSafe(r);
      if (!r.ok) {
        const err = json?.error || json?.message || text || "AI_ERROR";
        console.warn("[ai] chat fail", { status: r.status, attempt, ms: Date.now() - started, err: redact(err) });
        if (attempt <= retries && isRetryableStatus(r.status)) {
          await sleep(600 * attempt);
          continue;
        }
        return { ok: false, status: r.status, json, error: String(err) };
      }

      console.log("[ai] chat ok", { status: r.status, attempt, ms: Date.now() - started });
      return { ok: true, status: r.status, json, error: null };
    } catch (e) {
      const err = safeErr(e);
      const status = e?.name === "AbortError" ? 408 : 0;
      console.warn("[ai] chat exception", { status, attempt, ms: Date.now() - started, err: redact(err) });
      if (attempt <= retries) {
        await sleep(600 * attempt);
        continue;
      }
      return { ok: false, status, json: null, error: String(err) };
    } finally {
      clear();
    }
  }
}

